1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_PREMIUM = 60;
5	
6	type Item = { type: string };
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type Step = QuoteStep;
9	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const countByType = (items: Item[]): Map<string, number> => {
23	  const counts = new Map<string, number>();
24	  for (const item of items) {
25	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
26	  }
27	  return counts;
28	};
29	
30	const isCompleteBlock = (type: string, count: number): boolean =>
31	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
32	
33	const premiumForTypeCount = (type: string, count: number): number =>
34	  isCompleteBlock(type, count)
35	    ? BLOCK_PREMIUM
36	    : count * BASE_PREMIUMS[type];
37	
38	const basePremiumOf = (items: Item[]): number => {
39	  let total = 0;
40	  for (const [type, count] of countByType(items)) {
41	    total += premiumForTypeCount(type, count);
42	  }
43	  return total;
44	};
45	
46	const quoteForStep = ({ items }: QuoteStep) => {
47	  const basePremium = basePremiumOf(items);
48	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
49	  return { premium: Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE) };
50	};
51	
52	export const runScenario = (scenario: Scenario): unknown => {
53	  return { results: scenario.steps.map(quoteForStep) };
54	};
